import React, { useState, useEffect, useCallback } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  Chip,
  CircularProgress,
  Alert,
  IconButton,
  useTheme,
  useMediaQuery,
  Fade,
  Skeleton,
  Tooltip,
  Stack,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  TextField,
  Switch,
  FormControlLabel
} from '@mui/material';
import {
  Close,
  TrendingUp,
  TrendingDown,
  Refresh,
  History,
  Assessment,
  Timeline,
  Schedule,
  FilterList
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';
import { applyTradeFilters, filterFullyRealizedTrades } from '../../utils/tradeFilters';

const ClosedOperationsModal = ({ open, onClose }) => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  // Estados principais
  const [trades, setTrades] = useState([]);
  const [filteredTrades, setFilteredTrades] = useState([]);
  const [loading, setLoading] = useState(false);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState('');
  const [lastUpdate, setLastUpdate] = useState(null);
  // Removido progress state que causava re-renderizações

  // Estados de filtros
  const [filters, setFilters] = useState({
    fullyRealized: false, // Mostrar todas as operações por padrão
    period: 'all',
    symbol: '',
    side: 'all',
    result: 'all'
  });
  const [showFilters, setShowFilters] = useState(false);

  // Estados de estatísticas
  const [stats, setStats] = useState({
    totalTrades: 0,
    totalPnL: 0,
    winRate: 0,
    totalVolume: 0
  });

  // Timer visual de 30 segundos (igual ao OpenPositions)
  // Removido useEffect do progresso que causava re-renderizações constantes

  // Função para carregar trades com retry automático
  const loadTrades = useCallback(async (isRefresh = false) => {
    try {
      if (isRefresh) {
        setRefreshing(true);
      } else {
        setLoading(true);
        setTrades([]); // Limpar apenas no carregamento inicial
      }

      setError('');

      console.log('🔄 [ClosedOperationsModal] Carregando trades fechados...', { isRefresh });

      const response = await dashboardService.getClosedTrades();
      console.log('📊 [ClosedOperationsModal] Resposta da API:', response);

      // Processar resposta com validação robusta
      let tradesData = [];
      if (response?.trades && Array.isArray(response.trades)) {
        tradesData = response.trades;
      } else if (response?.data && Array.isArray(response.data)) {
        tradesData = response.data;
      } else if (Array.isArray(response)) {
        tradesData = response;
      }

      // Validar e limpar dados dos trades
      const validTrades = tradesData.filter(trade => {
        return trade && 
               trade.symbol && 
               trade.entry_price !== undefined && 
               trade.pnl !== undefined;
      }).map((trade, index) => {
        // Debug: verificar se marginCoin está presente
        if (index === 0) {
          console.log('🔍 [ClosedOperationsModal] Primeiro trade - campos de margem:', {
            margin: trade.margin,
            marginCoin: trade.marginCoin,
            allFields: Object.keys(trade)
          });
        }

        return {
          ...trade,
          id: trade.id || `${trade.symbol}_${trade.closed_at || Date.now()}_${index}_${Math.random().toString(36).substr(2, 9)}`,
          pnl: parseFloat(trade.pnl) || 0,
          roe: parseFloat(trade.roe) || 0,
          margin: parseFloat(trade.margin) || 0,
          marginCoin: trade.marginCoin || 'USDT', // Garantir que marginCoin tenha um valor padrão
          size: parseFloat(trade.size) || 0,
          entry_price: parseFloat(trade.entry_price) || 0,
          exit_price: parseFloat(trade.exit_price) || 0
        };
      });

      console.log('✅ [ClosedOperationsModal] Trades processados:', validTrades.length);

      setTrades(validTrades);
      setLastUpdate(new Date());

    } catch (error) {
      console.error('❌ [ClosedOperationsModal] Erro ao carregar trades:', error);
      setError(`Erro ao carregar operações encerradas: ${error.message || 'Erro desconhecido'}`);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  // Aplicar filtros quando os filtros ou trades mudarem
  useEffect(() => {
    if (trades.length > 0) {
      console.log('🔍 [ClosedOperationsModal] Aplicando filtros:', filters);
      console.log('📊 [ClosedOperationsModal] Trades antes dos filtros:', trades.length);

      const filtered = applyTradeFilters(trades, filters);

      console.log('📊 [ClosedOperationsModal] Trades após filtros:', filtered.length);

      setFilteredTrades(filtered);

      // Calcular estatísticas com base nos trades filtrados
      const newStats = calculateStats(filtered);
      setStats(newStats);
    } else {
      setFilteredTrades([]);
      setStats({ totalTrades: 0, totalPnL: 0, winRate: 0, totalVolume: 0 });
    }
  }, [filters, trades]);

  // Calcular estatísticas dos trades
  const calculateStats = (tradesData) => {
    if (!tradesData.length) {
      return { totalTrades: 0, totalPnL: 0, winRate: 0, totalVolume: 0 };
    }

    const totalTrades = tradesData.length;
    const totalPnL = tradesData.reduce((sum, trade) => sum + (trade.pnl || 0), 0);
    const winningTrades = tradesData.filter(trade => (trade.pnl || 0) > 0).length;
    const winRate = totalTrades > 0 ? (winningTrades / totalTrades) * 100 : 0;
    const totalVolume = tradesData.reduce((sum, trade) => sum + (trade.margin || 0), 0);

    return {
      totalTrades,
      totalPnL,
      winRate,
      totalVolume
    };
  };

  // Carregar dados quando o modal abrir
  useEffect(() => {
    if (open) {
      loadTrades();
    }
  }, [open, loadTrades]);

  // Auto-refresh a cada 30 segundos quando o modal estiver aberto (igual ao OpenPositions)
  useEffect(() => {
    if (!open) return;

    // Timer para atualização automática a cada 30 segundos
    const interval = setInterval(() => {
      loadTrades(true);
    }, 30000); // 30 segundos

    // Cleanup do timer quando o modal for fechado
    return () => clearInterval(interval);
  }, [open, loadTrades]);

  // Formatação de valores
  const formatCurrency = (value) => {
    if (value === null || value === undefined || isNaN(value)) return '$0.00';
    const numValue = typeof value === 'string' ? parseFloat(value) : value;
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 4
    }).format(numValue);
  };

  const formatPercentage = (value) => {
    if (value === null || value === undefined || isNaN(value)) return '0.00%';
    const numValue = typeof value === 'string' ? parseFloat(value) : value;
    return `${numValue >= 0 ? '+' : ''}${numValue.toFixed(2)}%`;
  };

  const formatDateTime = (dateString) => {
    if (!dateString) return '-';
    try {
      const date = new Date(dateString);
      return date.toLocaleString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      });
    } catch {
      return '-';
    }
  };

  // Componente para chip de lado (LONG/SHORT)
  const SideChip = ({ side }) => {
    const isLong = side?.toLowerCase() === 'long' || side?.toLowerCase() === 'buy';
    return (
      <Chip
        icon={isLong ? <TrendingUp /> : <TrendingDown />}
        label={isLong ? 'LONG' : 'SHORT'}
        color={isLong ? 'success' : 'error'}
        size="small"
        variant="filled"
        sx={{ fontWeight: 'bold', minWidth: 80 }}
      />
    );
  };

  // Componente de filtros
  const FiltersSection = () => (
    <Box sx={{ 
      p: 2, 
      bgcolor: 'background.paper',
      borderBottom: `1px solid ${theme.palette.divider}`,
    }}>
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: showFilters ? 2 : 0 }}>
        <Typography variant="subtitle2" color="text.secondary" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <FilterList fontSize="small" />
          Filtros
        </Typography>
        <Button
          size="small"
          onClick={() => setShowFilters(!showFilters)}
          startIcon={<FilterList />}
        >
          {showFilters ? 'Ocultar' : 'Mostrar'} Filtros
        </Button>
      </Box>

      {showFilters && (
        <Fade in={showFilters}>
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2, alignItems: 'center' }}>
            {/* Filtro de Operações Totalmente Realizadas */}
            <FormControlLabel
              control={
                <Switch
                  checked={filters.fullyRealized}
                  onChange={(e) => setFilters(prev => ({ ...prev, fullyRealized: e.target.checked }))}
                  color="primary"
                />
              }
              label="Apenas Totalmente Realizadas"
              sx={{ minWidth: 200 }}
            />

            {/* Filtro de Período */}
            <FormControl size="small" sx={{ minWidth: 120 }}>
              <InputLabel>Período</InputLabel>
              <Select
                value={filters.period}
                label="Período"
                onChange={(e) => setFilters(prev => ({ ...prev, period: e.target.value }))}
              >
                <MenuItem value="all">Todos</MenuItem>
                <MenuItem value="today">Hoje</MenuItem>
                <MenuItem value="week">Esta Semana</MenuItem>
                <MenuItem value="month">Este Mês</MenuItem>
              </Select>
            </FormControl>

            {/* Filtro de Símbolo */}
            <TextField
              size="small"
              label="Símbolo"
              placeholder="Ex: BTC, ETH"
              value={filters.symbol}
              onChange={(e) => setFilters(prev => ({ ...prev, symbol: e.target.value }))}
              sx={{ minWidth: 120 }}
            />

            {/* Filtro de Lado */}
            <FormControl size="small" sx={{ minWidth: 100 }}>
              <InputLabel>Lado</InputLabel>
              <Select
                value={filters.side}
                label="Lado"
                onChange={(e) => setFilters(prev => ({ ...prev, side: e.target.value }))}
              >
                <MenuItem value="all">Todos</MenuItem>
                <MenuItem value="long">Long</MenuItem>
                <MenuItem value="short">Short</MenuItem>
              </Select>
            </FormControl>

            {/* Filtro de Resultado */}
            <FormControl size="small" sx={{ minWidth: 120 }}>
              <InputLabel>Resultado</InputLabel>
              <Select
                value={filters.result}
                label="Resultado"
                onChange={(e) => setFilters(prev => ({ ...prev, result: e.target.value }))}
              >
                <MenuItem value="all">Todos</MenuItem>
                <MenuItem value="profit">Lucro</MenuItem>
                <MenuItem value="loss">Prejuízo</MenuItem>
              </Select>
            </FormControl>

            {/* Botão para limpar filtros */}
            <Button
              size="small"
              variant="outlined"
              onClick={() => setFilters({
                fullyRealized: false,
                period: 'all',
                symbol: '',
                side: 'all',
                result: 'all'
              })}
            >
              Limpar
            </Button>
          </Box>
        </Fade>
      )}
    </Box>
  );

  // Componente de estatísticas
  const StatsSection = () => (
    <Box sx={{ 
      p: 2, 
      bgcolor: 'background.paper',
      borderBottom: `1px solid ${theme.palette.divider}`,
      display: 'flex',
      justifyContent: 'space-around',
      flexWrap: 'wrap',
      gap: 2
    }}>
      <Box sx={{ textAlign: 'center', minWidth: 120 }}>
        <Typography variant="subtitle1" color="primary" sx={{ fontSize: '1.25rem', fontWeight: 600 }}>
          {stats.totalTrades}
        </Typography>
        <Typography variant="caption" color="text.secondary">
          Total de Operações
        </Typography>
      </Box>
      <Box sx={{ textAlign: 'center', minWidth: 120 }}>
        <Typography 
          variant="subtitle1" 
          color={stats.totalPnL >= 0 ? 'success.main' : 'error.main'}
          sx={{ fontWeight: 'bold', fontSize: '1.25rem' }}
        >
          {formatCurrency(stats.totalPnL)}
        </Typography>
        <Typography variant="caption" color="text.secondary">
          PnL Total
        </Typography>
      </Box>
      <Box sx={{ textAlign: 'center', minWidth: 120 }}>
        <Typography 
          variant="subtitle1" 
          color={stats.winRate >= 50 ? 'success.main' : 'warning.main'}
          sx={{ fontWeight: 'bold', fontSize: '1.25rem' }}
        >
          {stats.winRate.toFixed(1)}%
        </Typography>
        <Typography variant="caption" color="text.secondary">
          Taxa de Acerto
        </Typography>
      </Box>
    </Box>
  );

  // Componente de loading skeleton
  const LoadingSkeleton = () => (
    <Box sx={{ p: 2 }}>
      {[...Array(5)].map((_, index) => (
        <Skeleton key={index} variant="rectangular" height={60} sx={{ mb: 1 }} />
      ))}
    </Box>
  );

  // Renderizar conteúdo principal
  const renderContent = () => {
    if (loading) {
      return <LoadingSkeleton />;
    }

    if (filteredTrades.length === 0 && !loading) {
      const hasOriginalTrades = trades.length > 0;

      return (
        <Box sx={{ 
          display: 'flex', 
          flexDirection: 'column',
          alignItems: 'center', 
          justifyContent: 'center', 
          p: 6,
          minHeight: 300
        }}>
          <History sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
          <Typography variant="h5" color="text.secondary" gutterBottom>
            {hasOriginalTrades ? 'Nenhuma operação encontrada' : 'Nenhuma operação encerrada'}
          </Typography>
          <Typography variant="body1" color="text.secondary" textAlign="center">
            {hasOriginalTrades ? (
              <>
                Nenhuma operação corresponde aos filtros aplicados.
                <br />
                Tente ajustar os filtros ou limpar todos os filtros.
              </>
            ) : (
              <>
                As operações encerradas aparecerão aqui automaticamente.
                <br />
                Certifique-se de que suas credenciais da API estão configuradas corretamente.
              </>
            )}
          </Typography>
          {hasOriginalTrades ? (
            <Button 
              variant="outlined" 
              onClick={() => setFilters({
                fullyRealized: true,
                period: 'all',
                symbol: '',
                side: 'all',
                result: 'all'
              })} 
              sx={{ mt: 2 }}
              startIcon={<FilterList />}
            >
              Limpar Filtros
            </Button>
          ) : (
            <Button 
              variant="outlined" 
              onClick={() => loadTrades()} 
              sx={{ mt: 2 }}
              startIcon={<Refresh />}
            >
              Tentar Novamente
            </Button>
          )}
        </Box>
      );
    }

    return (
      <Fade in={true} timeout={500}>
        <TableContainer 
          component={Paper} 
          sx={{ 
            maxHeight: isMobile ? '50vh' : '60vh',
            position: 'relative',
            '& .MuiTableCell-head': {
              backgroundColor: theme.palette.grey[50],
              fontWeight: 'bold'
            }
          }}
        >
          {refreshing && (
            <Box sx={{
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              height: 3,
              bgcolor: 'primary.main',
              animation: 'pulse 1.5s ease-in-out infinite',
              '@keyframes pulse': {
                '0%': { opacity: 0.4 },
                '50%': { opacity: 1 },
                '100%': { opacity: 0.4 }
              },
              zIndex: 10
            }} />
          )}

          <Table stickyHeader size={isMobile ? 'small' : 'medium'}>
            <TableHead>
              <TableRow>
                <TableCell>Par</TableCell>
                <TableCell>Lado</TableCell>
                <TableCell align="right">Tamanho</TableCell>
                <TableCell align="right">Entrada</TableCell>
                <TableCell align="right">Saída</TableCell>
                <TableCell align="right">PnL</TableCell>
                <TableCell align="right">Comissão</TableCell>
                <TableCell align="right">ROE</TableCell>
                <TableCell>Data/Hora</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {filteredTrades.map((trade, index) => (
                <TableRow 
                  key={trade.id || `trade_${index}_${trade.symbol}_${trade.closed_at}`} 
                  hover 
                  sx={{ 
                    '&:nth-of-type(odd)': { 
                      backgroundColor: theme.palette.action.hover 
                    }
                  }}
                >
                  <TableCell>
                    <Typography variant="body2" sx={{ fontWeight: 'bold' }}>
                      {trade.symbol || '-'}
                    </Typography>
                    <Typography variant="caption" color="text.secondary">
                      {trade.leverage ? `${trade.leverage}x` : '50x'}
                    </Typography>
                  </TableCell>

                  <TableCell>
                    <SideChip side={trade.side} />
                  </TableCell>

                  <TableCell align="right">
                    <Typography variant="body2">
                      {trade.size > 0 ? trade.size.toFixed(4) : '-'}
                    </Typography>
                  </TableCell>

                  <TableCell align="right">
                    <Typography variant="body2" sx={{ fontWeight: 'medium' }}>
                      {formatCurrency(trade.entry_price)}
                    </Typography>
                  </TableCell>

                  <TableCell align="right">
                    <Typography variant="body2" sx={{ fontWeight: 'medium' }}>
                      {trade.exit_price !== null && trade.exit_price !== undefined ? formatCurrency(trade.exit_price) : '-'}
                    </Typography>
                  </TableCell>

                  <TableCell align="right">
                    <Typography
                      variant="body2"
                      sx={{
                        color: trade.pnl >= 0 ? 'success.main' : 'error.main',
                        fontWeight: 'bold'
                      }}
                    >
                      {formatCurrency(trade.pnl)}
                    </Typography>
                  </TableCell>

                  <TableCell align="right">
                    <Typography
                      variant="body2"
                      sx={{
                        color: 'warning.main',
                        fontWeight: 'medium'
                      }}
                    >
                      {trade.pnl > 0 ? formatCurrency(trade.pnl * 0.35) : formatCurrency(0)}
                    </Typography>
                  </TableCell>

                  <TableCell align="right">
                    <Typography
                      variant="body2"
                      sx={{
                        color: trade.roe >= 0 ? 'success.main' : 'error.main',
                        fontWeight: 'bold'
                      }}
                    >
                      {formatPercentage(trade.roe)}
                    </Typography>
                  </TableCell>

                  <TableCell>
                    <Typography variant="caption" color="text.secondary">
                      {formatDateTime(trade.closed_at)}
                    </Typography>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      </Fade>
    );
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="xl"
      fullWidth
      fullScreen={isMobile}
      PaperProps={{
        sx: {
          minHeight: isMobile ? '100vh' : '80vh',
          maxHeight: isMobile ? '100vh' : '90vh'
        }
      }}
    >
      <DialogTitle sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        borderBottom: `1px solid ${theme.palette.divider}`,
        py: 2
      }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, fontSize: '1.1rem', fontWeight: 600 }}>
          <History color="primary" sx={{ fontSize: 20 }} />
          📈 Operações Encerradas ({trades.length})
        </Box>

        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          {/* Timer visual removido */}

          <IconButton 
            onClick={() => loadTrades(true)} 
            disabled={loading || refreshing} 
            size="small"
          >
            <Refresh />
          </IconButton>

          <IconButton onClick={onClose} size="small">
            <Close />
          </IconButton>
        </Box>
      </DialogTitle>

      {/* Seção de Estatísticas */}
      <StatsSection />

      {/* Seção de Filtros */}
      <FiltersSection />

      <DialogContent sx={{ p: 0, overflow: 'hidden' }}>
        {error && (
          <Alert 
            severity="error" 
            sx={{ m: 2 }}
            action={
              <Button color="inherit" size="small" onClick={() => loadTrades()}>
                Tentar Novamente
              </Button>
            }
          >
            {error}
          </Alert>
        )}

        {renderContent()}
      </DialogContent>

      <DialogActions sx={{ 
        borderTop: `1px solid ${theme.palette.divider}`,
        bgcolor: 'background.default',
        justifyContent: 'space-between',
        px: 3,
        py: 2
      }}>
        <Typography variant="caption" color="text.secondary">
          {lastUpdate && (
            <>Última atualização: {lastUpdate.toLocaleTimeString()}</>  
          )}
          {refreshing && ' • Atualizando...'}
        </Typography>

        <Button 
          onClick={onClose} 
          variant="contained" 
          size="large"
          startIcon={<Close />}
        >
          Fechar
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default ClosedOperationsModal;
